import{V as t}from"./chunks/theme.C3DGj2Ge.js";import{c as r,o as i,j as e,a2 as l,a as o,G as s,k as n}from"./chunks/framework.DDIT__tB.js";const d={class:"tip custom-block"},g=JSON.parse('{"title":"📊 Diagram: Mobility as a Service (MaaS) System","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/pcm/maas.md","filePath":"examples/models/pcm/maas.md"}'),c={name:"examples/models/pcm/maas.md"},f=Object.assign(c,{setup(u){return(m,a)=>(i(),r("div",null,[a[2]||(a[2]=e("h1",{id:"📊-diagram-mobility-as-a-service-maas-system",tabindex:"-1"},[o("📊 Diagram: Mobility as a Service (MaaS) System "),e("a",{class:"header-anchor",href:"#📊-diagram-mobility-as-a-service-maas-system","aria-label":'Permalink to "📊 Diagram: Mobility as a Service (MaaS) System"'},"​")],-1)),e("div",d,[a[0]||(a[0]=e("p",{class:"custom-block-title"},"Available Online",-1)),a[1]||(a[1]=e("p",null,"This model (converted to a data flow diagram) is available to view using the online editor!",-1)),s(n(t),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/MaaSTicketSystem/maas.json&layout=true"})]),a[3]||(a[3]=l('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://link.springer.com/chapter/10.1007/978-3-658-39438-7_32" target="_blank" rel="noreferrer">View Full Main Source</a></p><p><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/MaaSTicketSystem" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundles</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>The MaaS ticketing system is a distributed system in which customers manage and operate a vehicle which generates data that needs to be collected, managed, analyzed and sufficiently secured.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li>MaaS: Mobility as a Service</li><li>STS: Short term secret</li><li>LTS: Long term secret</li></ul><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label description&quot;">​</a></h2><ul><li><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><h3 id="datagranularity" tabindex="-1">DataGranularity <a class="header-anchor" href="#datagranularity" aria-label="Permalink to &quot;DataGranularity&quot;">​</a></h3><ul><li><strong>FineGranular</strong>: Data containing fine granular information</li><li><strong>Aggregated</strong>: Data aggregated from multiple data sources</li></ul></li><li><h3 id="datatype" tabindex="-1">DataType <a class="header-anchor" href="#datatype" aria-label="Permalink to &quot;DataType&quot;">​</a></h3><ul><li><strong>LTS</strong>: Data is a long term secret</li><li><strong>STS</strong>: Data is a short term secret</li><li><strong>TripData</strong>: Data related to trip information</li><li><strong>VehicleInformation</strong>: Data concerned with the vehicle</li><li><strong>InvoiceValue</strong>: Invoice amount data</li><li><strong>InspectionResult</strong>: Result data of an inspection</li><li><strong>LoginData</strong>: Data used for login</li><li><strong>ContactInformation</strong>: Contact information of a customer</li><li><strong>CustomerPseudonym</strong>: Pseudonym of a customer</li></ul></li></ul></li><li><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><h3 id="role" tabindex="-1">Role <a class="header-anchor" href="#role" aria-label="Permalink to &quot;Role&quot;">​</a></h3><ul><li><strong>AnalysisStaff</strong>: Action performed by Analysis staff</li><li><strong>Inspector</strong>: Action performed by an inspector</li><li><strong>Customer</strong>: Actions performed by customers</li><li><strong>Vehicle</strong>: Actions performed by the vehicle</li><li><strong>SupportStaff</strong>: Actions performed by the performed staff</li><li><strong>BillingStaff</strong>: Actions performed by the billing staff</li><li><strong>Administrators</strong>: Actions performed by system administrators</li><li><strong>MoblityProvider</strong>: Actions performed by the mobility provider</li></ul></li><li><h3 id="statemachineaccesstype" tabindex="-1">StateMachineAccessType <a class="header-anchor" href="#statemachineaccesstype" aria-label="Permalink to &quot;StateMachineAccessType&quot;">​</a></h3><ul><li><strong>Read</strong>: Read-only operations accesses only</li><li><strong>Write</strong>: Write and read operations allowed</li></ul></li></ul></li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><ol><li>Fine granular trip, STS and LTS data never leaves the customer <ul><li><code>CNFR11: data DataGranularity.FineGranular DataType.TripData neverFlows vertex !Role.Customer</code></li><li><code>CNFR12: data DataGranularity.FineGranular DataType.STS neverFlows vertex !Role.Customer</code></li><li><code>CNFR13: data DataGranularity.FineGranular DataType.LTS neverFlows vertex !Role.Customer</code></li></ul></li><li>Trip data and vehicle data from the customer never reaches an inspector <ul><li><code>CNFR2: data DataType.TripData Role.Customer DataType.VehicleInformation Role.Vehicle neverFlows vertex Role.Inspector</code></li></ul></li><li>Fine granular trip, STS and LTS data from the customer never reaches analysis staff or an inspector <ul><li><code>CNFR31: data DataType.TripData Role.Customer DataGranularity.FineGranular neverFlows vertex Role.AnalysisStaff,Role.Inspector</code></li><li><code>CNFR32: data DataType.STS Role.Customer DataGranularity.FineGranular neverFlows vertex Role.AnalysisStaff,Role.Inspector</code></li><li><code>CNFR33: data DataType.LTS Role.Customer DataGranularity.FineGranular neverFlows vertex Role.AnalysisStaff,Role.Inspector</code></li></ul></li><li>Fine granular trip data from the customer never reaches analysis staff <ul><li><code>CNFR4: data Role.Customer DataType.TripData DataGranularity.FineGranular neverFlows vertex Role.AnalysisStaff</code></li></ul></li><li>Interfaces written to never flow to interfaces used in read-only <ul><li><code>INFR1: data WriteAction.$Write neverFlows vertex StateMachineAccessType.Read where present $Write</code></li></ul></li></ol><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2>',12))]))}});export{g as __pageData,f as default};
